class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int x) { val = x; }
}

class Solution {
    public TreeNode subtreeWithAllDeepest(TreeNode root) {
        return findDeepest(root).node;
    }

    private NodeHeight findDeepest(TreeNode node) {
        if (node == null) return new NodeHeight(null, 0);
        NodeHeight left = findDeepest(node.left);
        NodeHeight right = findDeepest(node.right);
        if (left.height == right.height) {
            return new NodeHeight(node, left.height + 1);
        }
        return left.height > right.height ? new NodeHeight(left.node, left.height + 1) : new NodeHeight(right.node, right.height + 1);
    }

    private class NodeHeight {
        TreeNode node;
        int height;

        NodeHeight(TreeNode node, int height) {
            this.node = node;
            this.height = height;
        }
    }
}
